index eaff897..35a8040 100644
--- a/mux.go
+++ b/mux.go
@@ -194,7 +194,14 @@ func (r *Router) ServeHTTP(w http.ResponseWriter, req *http.Request) {
 		// Clean path to canonical form and redirect.
 		if p := cleanPath(path); p != path {
 			w.Header().Set("Location", replaceURLPath(req.URL, p))
-			w.WriteHeader(http.StatusMovedPermanently)
+			// Use 308 (Permanent Redirect) for non-idempotent methods so that
+			// HTTP clients preserve the original method and body on the redirect.
+			// GET and HEAD are safe to redirect with 301 (browsers follow it as GET).
+			if req.Method == http.MethodGet || req.Method == http.MethodHead {
+				w.WriteHeader(http.StatusMovedPermanently)
+			} else {
+				w.WriteHeader(http.StatusPermanentRedirect)
+			}
 			return
 		}
 	}
